/* RTOS Task API - rtos_task.h */
#ifndef RTOS_TASK_H
#define RTOS_TASK_H

#include <stdint.h>

typedef void* task_handle_t;
typedef void (*task_func_t)(void *arg);

/* BREAKING: Priority enum values shifted upward; IDLE is no longer 0.
   Code comparing priority to raw integers or storing them as uint8_t
   and reloading will get wrong priority levels. */
typedef enum {
    TASK_PRIO_IDLE     = 1,
    TASK_PRIO_LOW      = 2,
    TASK_PRIO_NORMAL   = 3,
    TASK_PRIO_HIGH     = 4,
    TASK_PRIO_REALTIME = 5
} task_priority_t;

task_handle_t task_create(const char *name,
                          task_func_t func,
                          void *arg,
                          task_priority_t priority,
                          uint32_t stack_size);

void task_delete(task_handle_t handle);
void task_delay_ms(uint32_t ms);
void task_yield(void);

#endif /* RTOS_TASK_H */
